_:n2ca7f7320fc641cb9c59977c0fb902c1b1 sh:message "Referenced features must be present within current graph closure for  topological feature." ;
    sh:select """
        prefix rdf:     <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
        PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
        prefix geojson: <https://purl.org/geojson/vocab#>
        prefix topo: <https://purl.org/geojson/topo#>
        SELECT $this (topo:relatedFeatures as ?path) (?ref as ?value)
        WHERE {
         $this topo:relatedFeatures/rdf:rest*/rdf:first ?ref .
         $this a ?geomtype .
         FILTER ( ?geomtype != geojson:Polygon)
         FILTER NOT EXISTS { ?ref ?p ?o }
        }
""" .

